VALUES
  ('real-estate-moex-02462', 'real-estate', 'real-estate-moex-098-a7c7609b', 'sub-real-estate-04', NULL, 'single_choice', '下列對於合夥人之出資義務之論述，何者錯誤？', '["合夥人之出資義務不以金錢為限，亦可以其他具有財產價值之物、勞務或信用為出資內容", "各合夥人之出資及其他合夥財產，為合夥人全體分別共有", "合夥因損失而至資本減少時，除非合夥契約有特別訂立，否則合夥人無補充之增資義務", "合夥人之出資額，不以等額為限"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:12+00:00", "source_pdf_sha1": "b014528585ac", "answer_pdf_sha1": "113f68396279", "source_family": "moex-gov-tw", "moex": {"exam_code": "098220", "c": "601", "s": "2001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民法概要", "year": "098", "exam_name": "098年建築師、技師、消防設備師、不動產經紀人、記帳士、第二次消防設備士、語言治療師", "original_question_number": 20, "answer_corrected": false, "flags": ["answer_missing"], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-02463', 'real-estate', 'real-estate-moex-098-a7c7609b', 'sub-real-estate-04', NULL, 'single_choice', '下列何者非屬不動產物權？', '["地上權", "典權", "留置權", "地役權"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:12+00:00", "source_pdf_sha1": "b014528585ac", "answer_pdf_sha1": "113f68396279", "source_family": "moex-gov-tw", "moex": {"exam_code": "098220", "c": "601", "s": "2001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民法概要", "year": "098", "exam_name": "098年建築師、技師、消防設備師、不動產經紀人、記帳士、第二次消防設備士、語言治療師", "original_question_number": 21, "answer_corrected": false, "flags": ["answer_missing"], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-02464', 'real-estate', 'real-estate-moex-098-a7c7609b', 'sub-real-estate-04', NULL, 'single_choice', '甲將其土地設定抵押權於乙，其後該抵押權因擔保債權清償而消滅，但乙不塗銷抵押權登記，則甲得對 乙行使何種權利以塗銷該抵押權登記？', '["所有物返還請求權", "占有物返還請求權", "所有權除去妨害請求權", "占有除去妨害請求權"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:12+00:00", "source_pdf_sha1": "b014528585ac", "answer_pdf_sha1": "113f68396279", "source_family": "moex-gov-tw", "moex": {"exam_code": "098220", "c": "601", "s": "2001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民法概要", "year": "098", "exam_name": "098年建築師、技師、消防設備師、不動產經紀人、記帳士、第二次消防設備士、語言治療師", "original_question_number": 22, "answer_corrected": false, "flags": ["answer_missing"], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-02465', 'real-estate', 'real-estate-moex-098-a7c7609b', 'sub-real-estate-04', NULL, 'single_choice', '關於時效取得地上權，下列敘述何者錯誤？', '["時效取得地上權之土地，以他人未登記之土地為限", "占有人以建築物為目的而主張時效取得地上權者，不以該建築物係合法建物者為限", "共有人之一人以在他共有人土地行使地上權之意思而占有共有土地者，亦得主張時效取得地上權", "占有人於取得時效完成後，仍須辦理地上權登記完畢後始取得地上權"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:12+00:00", "source_pdf_sha1": "b014528585ac", "answer_pdf_sha1": "113f68396279", "source_family": "moex-gov-tw", "moex": {"exam_code": "098220", "c": "601", "s": "2001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民法概要", "year": "098", "exam_name": "098年建築師、技師、消防設備師、不動產經紀人、記帳士、第二次消防設備士、語言治療師", "original_question_number": 23, "answer_corrected": false, "flags": ["answer_missing"], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-02466', 'real-estate', 'real-estate-moex-098-a7c7609b', 'sub-real-estate-04', NULL, 'single_choice', '關於越界建築之規定，下列敘述何者錯誤？', '["適用之主體限於土地所有人及其他有權之土地、建築物或工作物之利用人，至於無權占有人則不適用之", "越界建築之人須非因故意或重大過失逾越地界者，始得請求鄰地所有人之容忍義務", "越界建築之房屋或工作物，限於領有建築執照或其他合法之建物，若違章建築則不得主張鄰地所有人 之容忍義務", "土地所有人越界建築者，鄰地所有人除得請求購買越界部分之土地外，亦得請求一併購買其因此而形 成之畸零地"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:12+00:00", "source_pdf_sha1": "b014528585ac", "answer_pdf_sha1": "113f68396279", "source_family": "moex-gov-tw", "moex": {"exam_code": "098220", "c": "601", "s": "2001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民法概要", "year": "098", "exam_name": "098年建築師、技師、消防設備師、不動產經紀人、記帳士、第二次消防設備士、語言治療師", "original_question_number": 24, "answer_corrected": false, "flags": ["answer_missing"], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-02467', 'real-estate', 'real-estate-moex-098-a7c7609b', 'sub-real-estate-04', NULL, 'single_choice', '甲乙丙共有一筆土地，應有部分均等，下列敘述何者錯誤？', '["應有部分指分別共有人對所有權在量上之比例", "甲得不經乙丙之同意而自由將其應有部分設定抵押權予第三人", "若甲欲出賣其應有部分予第三人時，乙丙得以同一價格共同主張優先購買", "設甲乙丙約定出賣應有部分時應得其他共有人之同意，而甲違反約定將其應有部分移轉登記予第三人， 則乙丙得主張該移轉無效而請求第三人塗銷登記"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:12+00:00", "source_pdf_sha1": "b014528585ac", "answer_pdf_sha1": "113f68396279", "source_family": "moex-gov-tw", "moex": {"exam_code": "098220", "c": "601", "s": "2001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民法概要", "year": "098", "exam_name": "098年建築師、技師、消防設備師、不動產經紀人、記帳士、第二次消防設備士、語言治療師", "original_question_number": 25, "answer_corrected": false, "flags": ["answer_missing"], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-02468', 'real-estate', 'real-estate-moex-098-a7c7609b', 'sub-real-estate-04', NULL, 'single_choice', '關於共有不動產之分管契約，下列敘述何者錯誤？', '["分管契約應由共有人全體協議訂立，若不能協議者得訴請法院裁判定之", "共有人就分管之特定部分出租於第三人時，毋庸得其他共有人之同意", "分管契約經登記後，對應有部分之受讓人亦具有效力", "分管契約訂有期限者，於期限屆滿前仍得經共有人全體協議而終止分管契約"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:12+00:00", "source_pdf_sha1": "b014528585ac", "answer_pdf_sha1": "113f68396279", "source_family": "moex-gov-tw", "moex": {"exam_code": "098220", "c": "601", "s": "2001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民法概要", "year": "098", "exam_name": "098年建築師、技師、消防設備師、不動產經紀人、記帳士、第二次消防設備士、語言治療師", "original_question_number": 26, "answer_corrected": false, "flags": ["answer_missing"], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-02469', 'real-estate', 'real-estate-moex-098-a7c7609b', 'sub-real-estate-04', NULL, 'single_choice', '關於地上權之消滅情形，下列敘述何者錯誤？', '["地上權未定有期限且未約定地租者，地上權人原則上得隨時拋棄其權利", "地上權未定有期限，但有支付地租之約定者，地上權人應於一年前通知土地所有人或支付一年分地租 始得拋棄", "地上權人積欠地租達兩年總額，經土地所有人定期催告，逾期仍不支付者，土地所有人得撤銷（終止） 地上權", "地上權因地上之工作物或竹木之滅失而消滅"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:12+00:00", "source_pdf_sha1": "b014528585ac", "answer_pdf_sha1": "113f68396279", "source_family": "moex-gov-tw", "moex": {"exam_code": "098220", "c": "601", "s": "2001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民法概要", "year": "098", "exam_name": "098年建築師、技師、消防設備師、不動產經紀人、記帳士、第二次消防設備士、語言治療師", "original_question_number": 27, "answer_corrected": false, "flags": ["answer_missing"], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-02470', 'real-estate', 'real-estate-moex-098-a7c7609b', 'sub-real-estate-04', NULL, 'single_choice', '下列何種物權不得作為權利抵押權之標的物？', '["地上權", "永佃權", "地役權", "典權"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:12+00:00", "source_pdf_sha1": "b014528585ac", "answer_pdf_sha1": "113f68396279", "source_family": "moex-gov-tw", "moex": {"exam_code": "098220", "c": "601", "s": "2001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民法概要", "year": "098", "exam_name": "098年建築師、技師、消防設備師、不動產經紀人、記帳士、第二次消防設備士、語言治療師", "original_question_number": 28, "answer_corrected": false, "flags": ["answer_missing"], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-02471', 'real-estate', 'real-estate-moex-098-a7c7609b', 'sub-real-estate-04', NULL, 'single_choice', '下列何者非屬典權人之權利？', '["轉典權", "找貼權", "留買權", "相鄰權（相鄰關係之準用）"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:12+00:00", "source_pdf_sha1": "b014528585ac", "answer_pdf_sha1": "113f68396279", "source_family": "moex-gov-tw", "moex": {"exam_code": "098220", "c": "601", "s": "2001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民法概要", "year": "098", "exam_name": "098年建築師、技師、消防設備師、不動產經紀人、記帳士、第二次消防設備士、語言治療師", "original_question_number": 29, "answer_corrected": false, "flags": ["answer_missing"], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL)
